4	interface ClppSettingsState {
5	  experimentalMode: boolean;
6	  defaultSchemaId: string | null;
7	  setExperimentalMode: (mode: boolean) => void;
8	  setDefaultSchemaId: (id: string | null) => void;
9	  reset: () => void;
10	}
11	
12	const initialState = {
13	  experimentalMode: false,
14	  defaultSchemaId: null,
15	};
16	
17	export const useClppSettingsStore = create<ClppSettingsState>()(
18	  persist(
19	    (set) => ({
20	      ...initialState,
21	      setExperimentalMode: (mode) => set({experimentalMode: mode}),
22	      setDefaultSchemaId: (id) => set({defaultSchemaId: id}),
23	      reset: () => set(initialState),
24	    }),
25	    {name: "clpp-settings"},
26	  ),
27	);
