import {Tabs, TabsContent, TabsList, TabsTrigger} from "@/components/ui/tabs";
import {useClppSettingsStore} from "@/features/clpp/stores/clpp-settings-store";

const ExploreTabs = ({children}: {children: React.ReactNode}) => {
    const experimentalMode = useClppSettingsStore((s) => s.experimentalMode);

    return (
        <Tabs defaultValue="logs">
            <TabsList>
                <TabsTrigger value="logs">Logs</TabsTrigger>
                {experimentalMode && (
                    <>
                        <TabsTrigger value="patterns">Patterns</TabsTrigger>
                        <TabsTrigger value="schema">Schema</TabsTrigger>
                        <TabsTrigger value="stats">Stats</TabsTrigger>
                    </>
                )}
            </TabsList>
            <TabsContent value="logs">
                {children}
            </TabsContent>
            {experimentalMode && (
                <>
                    <TabsContent value="patterns">
                        <div className="p-4 text-sm text-muted-foreground">Patterns tab — coming soon</div>
                    </TabsContent>
                    <TabsContent value="schema">
                        <div className="p-4 text-sm text-muted-foreground">Schema tab — coming soon</div>
                    </TabsContent>
                    <TabsContent value="stats">
                        <div className="p-4 text-sm text-muted-foreground">Stats tab — coming soon</div>
                    </TabsContent>
                </>
            )}
        </Tabs>
    );
};

export default ExploreTabs;

